import{_ as a,o as s,c as t,a4 as o}from"./chunks/framework.DyALjzgy.js";const p=JSON.parse('{"title":"IAM","description":"","frontmatter":{},"headers":[],"relativePath":"overview/components/iam.md","filePath":"overview/components/iam.md"}'),r={name:"overview/components/iam.md"};function n(i,e,l,m,d,c){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="iam" tabindex="-1">IAM <a class="header-anchor" href="#iam" aria-label="Permalink to &quot;IAM&quot;">​</a></h1><p>The <strong>IAM module</strong> handles identity and access management for Platform Mesh. It is composed of two layers:</p><ul><li><strong>Keycloak</strong> — the OIDC identity provider used for authentication. Users log in via Keycloak and receive JWT tokens consumed by all Platform Mesh services.</li><li><strong>OpenFGA</strong> — a relationship-based authorisation engine (inspired by Google Zanzibar). Fine-grained permissions (e.g. workspace membership, role assignments) are stored as tuples and evaluated by OpenFGA at request time.</li></ul><h2 id="iam-ui" tabindex="-1">IAM UI <a class="header-anchor" href="#iam-ui" aria-label="Permalink to &quot;IAM UI&quot;">​</a></h2><p>The <strong>IAM UI</strong> is the identity and access management microfrontend for Platform Mesh. It provides user and role management directly inside the Portal shell, giving workspace administrators full control over who can access a resource and with what permissions.</p><hr><h3 id="what-it-does" tabindex="-1">What It Does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What It Does&quot;">​</a></h3><p>IAM UI lets users manage membership and roles for any Platform Mesh resource (accounts, teams, namespaces, and other Kubernetes-scoped entities). The key capabilities are:</p><ul><li><strong>Browse members</strong> — paginated, searchable, and filterable list of all users assigned to a resource</li><li><strong>Add members</strong> — invite existing platform users or send email invitations to new users, assigning one or more roles in a single step</li><li><strong>Assign and remove roles</strong> — update role assignments inline; at least one owner is always enforced</li><li><strong>Leave a scope</strong> — a user can remove themselves from a resource they belong to</li></ul><hr>',10)])])}const u=a(r,[["render",n]]);export{p as __pageData,u as default};
